"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { motion } from "framer-motion";
import { 
  Users, 
  BookOpen, 
  Calendar, 
  Sprout, 
  TrendingUp, 
  LogOut,
  Bell,
  Search,
  Plus,
  ArrowRight,
  MessageSquare,
  HandCoins
} from "lucide-react";
import { Button } from "@/components/ui/button";
import api from "@/lib/api";
import Link from "next/link";
import { Badge } from "@/components/ui/badge";

const stats = [
  { label: "Active Students", value: "1,280", icon: Users, color: "blue" },
  { label: "Dhamma Teachings", value: "450", icon: Sprout, color: "bodhi" },
  { label: "Future Events", value: "12", icon: Calendar, color: "gold" },
];

interface AdminUser {
  id: string;
  name: string;
  email: string;
  role: string;
}

interface DashboardCounts {
  events: number;
  teachings: number;
  inquiries: number;
  unreadInquiries: number;
  unreadSponsors: number;
  pendingDonors: number;
}

interface Teaching {
  id: string;
  title: string;
  updatedAt: string;
}

export default function AdminDashboard() {
  const router = useRouter();
  const [adminUser, setAdminUser] = useState<AdminUser | null>(null);
  const [counts, setCounts] = useState<DashboardCounts>({ 
    events: 0, 
    teachings: 0, 
    inquiries: 0, 
    unreadInquiries: 0,
    unreadSponsors: 0,
    pendingDonors: 0 
  });
  const [recentTeachings, setRecentTeachings] = useState<Teaching[]>([]);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const user = localStorage.getItem("user");
    if (!token || !user) {
      localStorage.removeItem("token");
      localStorage.removeItem("user");
      router.push("/admin/login");
    } else {
      setAdminUser(JSON.parse(user));
    }

    const fetchStats = async () => {
      try {
        const [eventsRes, teachingsRes, contactRes, donorsRes, oneTimeRes] = await Promise.all([
          api.get("/events"),
          api.get("/teachings"),
          api.get("/contact"),
          api.get("/donations/monthly-donor-subscriptions"),
          api.get("/donations")
        ]);

        const contactData = contactRes.data.data || contactRes.data || [];
        const unreadInquiries = contactData.filter((i: { isRead: boolean; eventId: string | null }) => !i.isRead && !i.eventId).length;
        const unreadSponsors = contactData.filter((i: { isRead: boolean; eventId: string | null }) => !i.isRead && !!i.eventId).length;

        const donorsData = donorsRes.data.data || donorsRes.data || [];
        const oneTimeData = oneTimeRes.data.data || oneTimeRes.data || [];
        const pendingDonors = donorsData.filter((d: { status: string }) => d.status === "pending").length + oneTimeData.filter((d: { status: string }) => d.status === "pending").length;

        setCounts({
          events: eventsRes.data.meta?.total || eventsRes.data.length || 0,
          teachings: teachingsRes.data.meta?.total || teachingsRes.data.length || 0,
          inquiries: contactData.length || 0,
          unreadInquiries,
          unreadSponsors,
          pendingDonors
        });
        setRecentTeachings((teachingsRes.data.data || teachingsRes.data || []).slice(0, 5) as Teaching[]);
      } catch (err) {
        console.error("Failed to fetch dashboard stats", err);
      }
    };

    fetchStats();
  }, [router]);

  const totalNotifications = counts.unreadInquiries + counts.unreadSponsors + counts.pendingDonors;

  const dashboardStats = [
    { label: "Future Events", value: counts.events, icon: Calendar, color: "gold" },
    { label: "Dhamma Teachings", value: counts.teachings, icon: Sprout, color: "bodhi" },
    { label: "New Messages", value: counts.unreadInquiries, icon: Bell, color: "navy" },
    { label: "Pending Slips", value: counts.pendingDonors, icon: HandCoins, color: "bodhi" },
  ];

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    router.push("/admin/login");
  };

  if (!adminUser) return null;

  return (
    <div className="min-h-screen bg-cream/10 p-6 md:p-10 font-sans">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <h1 className="text-4xl font-black text-maroon tracking-tight mb-2 uppercase">
              Dashboard <span className="text-gold">Overview</span>
            </h1>
            <p className="text-navy/50 font-myanmar font-medium">
              မင်္ဂလာပါ {adminUser.name} - စီမံခန့်ခွဲရေး အနှစ်ချုပ်ကို ကြည့်ရှုနေပါသည်။
            </p>
          </div>

          <div className="flex items-center gap-4">
            <div className="relative group">
              <button className="relative size-12 rounded-2xl bg-white border border-gold/20 flex items-center justify-center text-navy/40 hover:text-maroon transition-colors shadow-sm cursor-pointer">
                <Bell className="size-6 group-hover:rotate-12 transition-transform" />
                {totalNotifications > 0 && (
                  <span className="absolute -top-1 -right-1 size-5 bg-red-500 text-white text-[10px] font-black rounded-full flex items-center justify-center border-2 border-white animate-bounce-slow">
                    {totalNotifications}
                  </span>
                )}
              </button>

              {/* Notification Popover on Hover */}
              <div className="absolute top-full right-0 pt-2 w-64 opacity-0 translate-y-2 pointer-events-none group-hover:opacity-100 group-hover:translate-y-0 group-hover:pointer-events-auto transition-all z-50">
                <div className="bg-white border border-gold/20 rounded-2xl shadow-2xl overflow-hidden">
                  <div className="p-4 border-b border-gold/5 bg-cream/30">
                    <p className="text-xs font-black text-maroon uppercase tracking-widest">Notifications</p>
                  </div>
                  <div className="p-2">
                    <Link href="/admin/inquiries" className="flex items-center justify-between p-3 rounded-xl hover:bg-cream/50 transition-colors">
                      <div className="flex items-center gap-3">
                        <div className="size-8 rounded-lg bg-gold/10 flex items-center justify-center">
                          <MessageSquare className="size-4 text-gold-dark" />
                        </div>
                        <span className="text-sm font-bold text-navy/70">Messages</span>
                      </div>
                      {counts.unreadInquiries > 0 && (
                        <Badge className="bg-gold text-white text-[10px]">{counts.unreadInquiries}</Badge>
                      )}
                    </Link>
                    <Link href="/admin/events" className="flex items-center justify-between p-3 rounded-xl hover:bg-cream/50 transition-colors">
                      <div className="flex items-center gap-3">
                        <div className="size-8 rounded-lg bg-orange-100 flex items-center justify-center">
                          <Calendar className="size-4 text-orange-600" />
                        </div>
                        <span className="text-sm font-bold text-navy/70">Event Sponsors</span>
                      </div>
                      {counts.unreadSponsors > 0 && (
                        <Badge className="bg-orange-500 text-white text-[10px]">{counts.unreadSponsors}</Badge>
                      )}
                    </Link>
                    <Link href="/admin/donations" className="flex items-center justify-between p-3 rounded-xl hover:bg-cream/50 transition-colors">
                      <div className="flex items-center gap-3">
                        <div className="size-8 rounded-lg bg-bodhi/10 flex items-center justify-center">
                          <HandCoins className="size-4 text-bodhi" />
                        </div>
                        <span className="text-sm font-bold text-navy/70">Pending Slips</span>
                      </div>
                      {counts.pendingDonors > 0 && (
                        <Badge className="bg-bodhi text-white text-[10px]">{counts.pendingDonors}</Badge>
                      )}
                    </Link>
                  </div>
                </div>
              </div>
            </div>

            <Button
              onClick={handleLogout}
              variant="outline"
              className="h-12 border-maroon/20 text-maroon hover:bg-maroon hover:text-white rounded-xl font-bold px-6 shadow-sm"
            >
              <LogOut className="size-4 mr-2" /> Logout
            </Button>
          </div>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          {dashboardStats.map((stat, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
              className="bg-white p-8 rounded-[2rem] border border-gold/10 shadow-xl shadow-maroon/5 flex items-center gap-6 group hover:border-gold transition-all"
            >
              <div className="size-16 rounded-2xl bg-cream flex items-center justify-center group-hover:bg-maroon transition-colors">
                <stat.icon className="size-8 text-maroon group-hover:text-gold transition-colors" />
              </div>
              <div>
                <p className="text-xs font-black text-navy/30 uppercase tracking-widest mb-1">
                  {stat.label}
                </p>
                <p className="text-2xl font-black text-navy tracking-tight">
                  {stat.value}
                </p>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Quick Actions */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
          <div className="lg:col-span-2 space-y-10">
            {/* Recent Teachings Section */}
            <section className="bg-white rounded-[3rem] border border-gold/10 p-10 shadow-xl shadow-maroon/5">
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-black text-maroon uppercase tracking-tight">
                  Recent Teachings
                </h2>
                <Link href="/admin/teachings">
                  <Button variant="ghost" className="text-gold hover:text-maroon font-bold">
                    View All <ArrowRight className="size-4 ml-2" />
                  </Button>
                </Link>
              </div>

              <div className="space-y-4">
                {recentTeachings.map((teaching) => (
                  <div key={teaching.id} className="flex items-center justify-between p-6 rounded-2xl bg-cream/30 border border-gold/5 hover:border-gold/20 transition-all">
                    <div className="flex items-center gap-4">
                      <div className="size-12 rounded-xl bg-maroon/10 flex items-center justify-center">
                        <Sprout className="size-6 text-maroon" />
                      </div>
                      <div>
                        <p className="font-bold text-navy">{teaching.title}</p>
                        <p className="text-xs text-navy/40">Updated {new Date(teaching.updatedAt).toLocaleDateString()}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </section>
          </div>

          <div className="space-y-6">
            <h2 className="text-xl font-black text-maroon uppercase tracking-tight ml-4">
              Quick Actions
            </h2>
            <div className="space-y-4">
              <QuickButton href="/admin/events/new" label="Schedule Event" icon={Calendar} color="gold" />
              <QuickButton href="/admin/teachings/new" label="Post Teaching" icon={Sprout} color="bodhi" />
              <QuickButton href="/admin/donations" label="Manage Donations" icon={TrendingUp} color="navy" />
              <QuickButton href="/admin/dashboard" label="View Analytics" icon={TrendingUp} color="navy" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function QuickButton({ label, icon: Icon, color, href }: { label: string; icon: any; color: string; href: string }) {
  return (
    <Link href={href || "#"}>
      <button className="w-full h-20 bg-white hover:bg-cream rounded-[1.5rem] border border-gold/10 hover:border-gold/50 transition-all p-6 flex items-center justify-between group shadow-sm mb-4">
        <div className="flex items-center gap-4">
          <div className="size-10 rounded-xl bg-navy/5 flex items-center justify-center group-hover:bg-maroon transition-colors">
            <Icon className="size-5 text-navy group-hover:text-white transition-colors" />
          </div>
          <span className="font-bold text-navy group-hover:text-maroon transition-colors">{label}</span>
        </div>
        <ArrowRight className="size-5 text-gold group-hover:translate-x-1 transition-transform" />
      </button>
    </Link>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useTranslation } from "@/providers/LanguageProvider";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import api from "@/lib/api";
import { HandCoins, History } from "lucide-react";
import { AddDonationModal } from "@/components/admin/donations/AddDonationModal";
import { DataTable, Column } from "@/components/admin/DataTable";

interface Donation {
  id: string;
  donorName: string;
  amount: number;
  currency: string;
  category: string;
  message?: string;
  slipUrl?: string;
  status: string;
  date?: string;
  createdAt: string;
}

interface PaginationMeta {
  total: number;
  page: number;
  limit: number;
  totalPages: number;
  totalsByCurrency?: Array<{ currency: string; total: number }>;
}

export default function AdminDonationsPage() {
  const { t } = useTranslation();
  const [isLoading, setIsLoading] = useState(true);
  const [rows, setRows] = useState<Donation[]>([]);
  const [meta, setMeta] = useState<PaginationMeta | null>(null);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [sortBy, setSortBy] = useState("createdAt");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");
  const [categoryFilter, setCategoryFilter] = useState("");
  const [statusFilter, setStatusFilter] = useState("");
  const [refreshKey, setRefreshKey] = useState(0);
  const limit = 20;

  const updateStatus = async (id: string, newStatus: string) => {
    try {
      await api.put(`/donations/${id}`, { status: newStatus });
      setRefreshKey(k => k + 1);
    } catch (e) {
      console.error(e);
      alert("Failed to update status.");
    }
  };

  const deleteDonation = async (id: string) => {
    if (!confirm("Are you sure you want to delete this donation?")) return;
    try {
      await api.delete(`/donations/${id}`);
      setRefreshKey(k => k + 1);
    } catch (e) {
      console.error(e);
      alert("Failed to delete donation.");
    }
  };


  useEffect(() => {
    let cancelled = false;
    const fetchDonations = async () => {
      setIsLoading(true);
      try {
        const res = await api.get("/donations", {
          params: { 
            page, 
            limit, 
            search: search.trim(),
            sortBy,
            sortOrder,
            ...(categoryFilter ? { category: categoryFilter } : {}),
            ...(statusFilter ? { status: statusFilter } : {})
          },
        });
        if (cancelled) return;
        setRows(res.data.data ?? []);
        setMeta(res.data.meta ?? null);
      } catch (e) {
        if (!cancelled) {
          setRows([]);
          setMeta(null);
        }
      } finally {
        if (!cancelled) setIsLoading(false);
      }
    };

    const timeout = setTimeout(fetchDonations, 300);
    return () => { cancelled = true; clearTimeout(timeout); };
  }, [page, search, refreshKey, sortBy, sortOrder, categoryFilter, statusFilter]);

  const columns: Column<Donation>[] = [
    {
      id: "donorName",
      header: "Donor",
      sortable: true,
      accessorKey: "donorName",
      cell: (d: Donation) => <p className="font-black text-navy tracking-tight">{d.donorName}</p>
    },
    {
      id: "amount",
      header: "Amount",
      sortable: true,
      cell: (d: Donation) => (
        <div className="flex items-baseline gap-2">
          <p className="font-black text-maroon text-lg">
            {Number(d.amount || 0).toLocaleString("en-US", { maximumFractionDigits: 2 })}
          </p>
          <p className="text-xs font-black text-navy/40 uppercase tracking-widest">{d.currency}</p>
        </div>
      )
    },
    {
      id: "category",
      header: "Category",
      sortable: true,
      cell: (d: Donation) => (
        <Badge variant="outline" className="bg-navy/5 text-navy/70 border-navy/10 capitalize">
          {t(`donors.monthly.categories.${d.category || 'general'}`)}
        </Badge>
      )
    },
    {
      id: "message",
      header: "Message",
      className: "max-w-xl",
      cell: (d: Donation) => <p className="text-sm text-navy/60 line-clamp-2">{d.message || "-"}</p>
    },
    {
      id: "date",
      header: "Date",
      sortable: true,
      cell: (d: Donation) => {
        const date = d.date || d.createdAt;
        return (
          <p className="text-sm font-bold text-navy/60">
            {date ? new Date(date).toLocaleString() : "-"}
          </p>
        );
      }
    },
    {
      id: "status",
      header: "Status / Slip",
      cell: (d: Donation) => {
        const backendBaseUrl = (process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000/api').replace('/api', '');
        return (
          <div className="flex flex-col gap-2 items-start">
            <Badge 
              variant="outline" 
              className={`capitalize ${d.status === 'pending' ? 'bg-yellow-100 text-yellow-800 border-yellow-200' : 'bg-green-100 text-green-800 border-green-200'}`}
            >
              {d.status || "approved"}
            </Badge>
            {d.slipUrl && (
              <a href={`${backendBaseUrl}${d.slipUrl}`} target="_blank" rel="noreferrer" className="text-[10px] text-maroon font-bold uppercase tracking-widest hover:underline whitespace-nowrap">
                 View Slip
              </a>
            )}
          </div>
        );
      }
    },
    {
      id: "actions",
      header: "Actions",
      className: "text-right",
      cell: (d: Donation) => (
        <div className="flex items-center justify-end gap-2 text-right">
          {(!d.status || d.status === "pending") && (
            <Button
              size="sm"
              variant="outline"
              className="text-green-700 bg-green-50 hover:bg-green-100 border-green-200"
              onClick={() => updateStatus(d.id, "approved")}
            >
              Approve
            </Button>
          )}
          <Button
            size="sm"
            variant="outline"
            className="text-red-700 bg-red-50 hover:bg-red-100 border-red-200"
            onClick={() => deleteDonation(d.id)}
          >
            Delete
          </Button>
        </div>
      )
    }
  ];

  return (
    <div className="p-8 md:p-12 space-y-10">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-maroon tracking-tight mb-2 uppercase">
            Donations <span className="text-gold">Management</span>
          </h1>
          <p className="text-navy/50 font-myanmar font-medium">
            View all donations submitted (Total: {meta?.total ?? 0})
          </p>
        </div>

        <div className="flex flex-wrap gap-4 items-center justify-end">
          <AddDonationModal onSuccess={() => setRefreshKey(k => k + 1)} />
          <Link href="/admin/monthly-donors/report">
            <Button className="h-14 bg-navy hover:bg-navy/80 text-white rounded-2xl px-6 font-black text-base shadow-lg shadow-navy/20">
              <History className="mr-2 size-5" /> Reports
            </Button>
          </Link>
          <Link href="/admin/monthly-donors">
            <Button className="h-14 bg-gold hover:bg-gold/80 text-navy rounded-2xl px-6 font-black text-base shadow-lg shadow-gold/20">
              <HandCoins className="mr-2 size-5" /> Subscriptions
            </Button>
          </Link>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {["MMK", "USD", "THB", "SGD"].map((curr) => {
          const amount = meta?.totalsByCurrency?.find((t: { currency: string }) => t.currency === curr)?.total || 0;
          return (
            <div key={curr} className="bg-cream/20 p-6 rounded-[2rem] border border-gold/10">
              <p className="text-[10px] font-black text-navy/30 uppercase tracking-[0.2em] mb-1">{curr}</p>
              <p className="text-2xl font-black text-maroon">{amount.toLocaleString()}</p>
            </div>
          );
        })}
      </div>

      <DataTable
        columns={columns}
        data={rows}
        isLoading={isLoading}
        search={search}
        onSearchChange={(v) => { setSearch(v); setPage(1); }}
        sortBy={sortBy}
        sortOrder={sortOrder}
        onSort={(f, o) => { setSortBy(f); setSortOrder(o); }}
        page={page}
        totalPages={meta?.totalPages || 1}
        total={meta?.total}
        onPageChange={setPage}
      >
        <select
          value={categoryFilter}
          onChange={(e) => {
            setCategoryFilter(e.target.value);
            setPage(1);
          }}
          className="h-12 bg-cream/30 border-none rounded-xl px-4 focus:ring-2 focus:ring-maroon/20 outline-none font-bold text-navy/70 text-sm cursor-pointer"
        >
          <option value="">All Categories</option>
          {["robes", "alms", "monastery", "medicine", "education", "general"].map(cat => (
            <option key={cat} value={cat}>{t(`donors.monthly.categories.${cat}`)}</option>
          ))}
        </select>

        <select
          value={statusFilter}
          onChange={(e) => {
            setStatusFilter(e.target.value);
            setPage(1);
          }}
          className="h-12 bg-cream/30 border-none rounded-xl px-4 focus:ring-2 focus:ring-maroon/20 outline-none font-bold text-navy/70 text-sm cursor-pointer"
        >
          <option value="">All Statuses</option>
          <option value="pending">Pending</option>
          <option value="approved">Approved</option>
        </select>
      </DataTable>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { EventForm } from "@/components/admin/EventForm";
import { ChevronLeft, Loader2 } from "lucide-react";
import Link from "next/link";
import api from "@/lib/api";
import { useParams } from "next/navigation";

export default function EditEventPage() {
  const params = useParams();
  const [event, setEvent] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        const response = await api.get(`/events/${params.id}`);
        setEvent(response.data);
      } catch (error) {
        console.error("Error fetching event:", error);
      } finally {
        setIsLoading(false);
      }
    };

    if (params.id) {
      fetchEvent();
    }
  }, [params.id]);

  if (isLoading) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center gap-4 text-maroon/30">
        <Loader2 className="size-10 animate-spin" />
        <span className="font-bold uppercase tracking-widest text-xs">Loading Event Details...</span>
      </div>
    );
  }

  if (!event) {
    return (
      <div className="p-12 text-center">
        <h2 className="text-2xl font-bold text-maroon">Event not found</h2>
        <Link href="/admin/events" className="text-gold hover:underline mt-4 block">
          Back to Events
        </Link>
      </div>
    );
  }

  return (
    <div className="p-8 md:p-12 space-y-10">
