export default function AdminMonthlyDonorsPage() {
  const { t } = useTranslation();
  const [donors, setDonors] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [sortBy, setSortBy] = useState("createdAt");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");
  const [categoryFilter, setCategoryFilter] = useState("");
  const [meta, setMeta] = useState<any | null>(null);
  const [savingId, setSavingId] = useState<string | null>(null);
  const limit = 20;

  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [donorToDelete, setDonorToDelete] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const fetchDonors = async () => {
    setIsLoading(true);
    try {
      const res = await api.get("/donations/monthly-donor-subscriptions", {
        params: { 
          page, 
          limit, 
          search: search.trim(),
          sortBy,
          sortOrder,
          category: categoryFilter,
        },
      });
      setDonors(res.data.data);
      setMeta(res.data.meta);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    const delayDebounceFn = setTimeout(() => {
      fetchDonors();
    }, 500);
    return () => clearTimeout(delayDebounceFn);
  }, [page, search, sortBy, sortOrder, categoryFilter]);

  const updateStatus = async (id: string, newStatus: string) => {
    setSavingId(id);
    try {
      await api.put(`/donations/monthly-donor-subscriptions/${id}`, { status: newStatus });
      fetchDonors();
    } catch (err) {
      alert("Failed to update status");
    } finally {
      setSavingId(null);
    }
  };

  const deleteDonor = async (id: string | null) => {
    if (typeof id === "string") {
      setDonorToDelete(id);
      setIsDeleteModalOpen(true);
      return;
    }

    if (!donorToDelete) return;

    setIsDeleting(true);
    try {
      await api.delete(`/donations/monthly-donor-subscriptions/${donorToDelete}`);
      toast.success("Subscription deleted successfully!");
      fetchDonors();
      setIsDeleteModalOpen(false);
      setDonorToDelete(null);
    } catch (err) {
      toast.error("Failed to delete subscription.");
    } finally {
      setIsDeleting(false);
    }
  };

  const columns: Column<any>[] = [
    {
      id: "name",
      header: "Donor Name",
      sortable: true,
      cell: (donor) => (
        <div>
          <p className="font-bold text-navy text-base">{donor.name}</p>
          {donor.remarks && (
            <p className="text-xs text-navy/50 italic mt-1 line-clamp-1 max-w-[200px]" title={donor.remarks}>
              {donor.remarks}
            </p>
          )}
        </div>
      )
    },
    {
