                      </div>
                    ) : (
                      <div className="p-10 bg-cream/5 border border-dashed border-gold/20 rounded-3xl text-center">
                        <p className="text-navy/50 text-sm font-medium">
                          This file can be downloaded and read using your preferred eBook reader.
                        </p>
                      </div>
                    )}
                  </div>

                  {/* Reading Tools Panel */}
                  <div className={`w-full lg:w-80 flex flex-col gap-6 ${isMaximized ? "lg:overflow-y-auto lg:pr-2" : ""}`}>
                    {/* Progression & Stats */}
                    <div className="bg-cream/20 rounded-[2rem] p-6 border border-gold/10 space-y-6">
                      <div className="space-y-1">
                        <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-maroon flex items-center gap-2">
                          <BookOpen className="size-3.5" /> Reading Progress
                        </h3>
                        <div className="flex items-baseline justify-between">
                          <span className="text-2xl font-black text-navy">{totalPage > 0 ? Math.round((currentPage / totalPage) * 100) : 0}%</span>
                          <span className="text-[10px] font-bold text-navy/40 uppercase">Completed</span>
                        </div>
                        <div className="h-2 w-full bg-navy/5 rounded-full overflow-hidden">
                          <div
                            className="h-full bg-linear-to-r from-maroon to-gold transition-all duration-1000 ease-out"
                            style={{ width: `${totalPage > 0 ? (currentPage / totalPage) * 100 : 0}%` }}
                          />
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-navy/30 uppercase tracking-widest block">Current Page</label>
                          <input
                            type="number"
                            min="1"
                            value={currentPage}
                            onChange={(e) => setCurrentPage(Math.max(1, parseInt(e.target.value) || 1))}
                            className="w-full h-11 bg-white border border-gold/20 rounded-xl px-3 text-sm font-black text-navy focus:outline-none focus:ring-2 focus:ring-maroon/20 focus:border-maroon transition-all"
                          />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-navy/30 uppercase tracking-widest block">Total Pages</label>
                          <input
                            type="number"
                            min="0"
                            value={totalPage}
                            onChange={(e) => setTotalPage(Math.max(0, parseInt(e.target.value) || 0))}
                            className="w-full h-11 bg-white border border-gold/20 rounded-xl px-3 text-sm font-black text-navy focus:outline-none focus:ring-2 focus:ring-maroon/20 focus:border-maroon transition-all"
                          />
                        </div>
                      </div>

                      <div className="space-y-4 pt-4 border-t border-gold/10">
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-2 uppercase tracking-tighter">
                            <Clock className="size-3.5 text-maroon" />
                            <span className="text-[10px] font-black text-navy/50">Time Spent</span>
                          </div>
                          <span className="text-xs font-black text-navy">
                            {Math.floor((totalSpentTime + sessionTime) / 60)}m {((totalSpentTime + sessionTime) % 60).toString().padStart(2, "0")}s
                          </span>
                        </div>
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-2 uppercase tracking-tighter">
                            <Calendar className="size-3.5 text-maroon" />
                            <span className="text-[10px] font-black text-navy/50">Last Active</span>
                          </div>
                          <span className="text-xs font-black text-navy">
                            {lastReadDate ? new Date(lastReadDate).toLocaleDateString() : "New"}
                          </span>
                        </div>
                      </div>
                    </div>

                    {/* Notes Area */}
                    <div className="bg-white rounded-[2rem] p-6 border border-gold/10 flex-1 flex flex-col gap-3 min-h-[250px]">
                      <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-maroon flex items-center gap-2">
                        <StickyNote className="size-3.5" /> Study Notes
                      </h3>
                      <textarea
                        value={notes}
                        onChange={(e) => setNotes(e.target.value)}
                        placeholder="Write your personal reflections or key takeaways here..."
                        className="flex-1 w-full bg-cream/5 border border-gold/10 rounded-2xl p-4 text-sm leading-relaxed text-navy/70 placeholder:text-navy/20 focus:outline-none focus:ring-2 focus:ring-maroon/20 focus:border-maroon transition-all resize-none"
                      />
                    </div>

                    <button
                      onClick={saveProgress}
                      className="group relative h-14 w-full bg-maroon text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-gold hover:text-navy transition-all duration-300 shadow-xl shadow-maroon/10"
                    >
                      <Save className="size-4 group-hover:scale-110 transition-transform" />
                      Save My Progress
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </section>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { motion } from "framer-motion";
import { Badge } from "@/components/ui/badge";
import { Sprout, FileText, ArrowUpRight, Loader2, Music2, Video, Globe } from "lucide-react";
import api from "@/lib/api";
import Link from "next/link";
import { resolveFileUrl } from "@/lib/fileUrl";
import { cn } from "@/lib/utils";
import { collectSearchText, pickTranslation } from "@/lib/translations";
import Image from "next/image";

export default function TeachingsPage() {
  const [teachings, setTeachings] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [selectedLanguage, setSelectedLanguage] = useState<"all" | "mm" | "en" | "th">("all");
  const [sortOrder, setSortOrder] = useState<"newest" | "oldest">("newest");

  useEffect(() => {
    const fetchTeachings = async () => {
      try {
        const response = await api.get("/teachings/published");
        setTeachings(response.data || []);
      } catch (error) {
        console.error("Failed to fetch teachings:", error);
      } finally {
        setIsLoading(false);
      }
    };
    fetchTeachings();
  }, []);

  const categories = useMemo(() => {
    const CANONICAL = [
      { id: "dhamma", label: "Dhamma" },
      { id: "dhamma_book", label: "Dhamma Book" },
      { id: "sutra", label: "Sutra" },
      { id: "vinaya", label: "Vinaya" },
      { id: "abhidhamma", label: "Abhidhamma" },
      { id: "meditation", label: "Meditation" },
      { id: "chanting", label: "Chanting" },
      { id: "other", label: "Other" },
    ];

    const counts = new Map<string, number>();

    teachings.forEach((t) => {
      const key = t.category ? String(t.category).toLowerCase() : "other";
      counts.set(key, (counts.get(key) || 0) + 1);
    });

    return [{ id: "all", label: "All", count: teachings.length }].concat(
      CANONICAL.map((cat) => ({
        ...cat,
        count: counts.get(cat.id) || 0,
      }))
    );
  }, [teachings]);

  const filteredTeachings = teachings.filter((teaching) => {
    // If filtering books, only show items with a document.
    if (selectedCategory === "dhamma_book" && !teaching.documentUrl) return false;

    const translations = Array.isArray(teaching.translations) ? teaching.translations : [];
    const languageFilteredTranslations =
      selectedLanguage === "all"
        ? translations
        : translations.filter((t: any) => t?.locale === selectedLanguage);

    const matchesLanguage =
      selectedLanguage === "all" || languageFilteredTranslations.length > 0;

    const searchText = collectSearchText(languageFilteredTranslations);
    const matchesSearch = searchText.includes(search.toLowerCase());
    const matchesCategory =
      selectedCategory === "all" ||
      (teaching.category && teaching.category.toLowerCase() === selectedCategory);
    return matchesLanguage && matchesSearch && matchesCategory;
  });

  const sortedTeachings = [...filteredTeachings].sort((a, b) => {
    const aTime = new Date(a.createdAt || 0).getTime();
    const bTime = new Date(b.createdAt || 0).getTime();
    return sortOrder === "newest" ? bTime - aTime : aTime - bTime;
  });

  return (
    <div className="min-h-screen bg-cream/10 pt-20">
      <section className="container mx-auto px-4 py-20">
        <div className="max-w-4xl mx-auto text-center mb-16">
          <Badge className="bg-maroon/10 text-maroon hover:bg-maroon/20 mb-6 px-4 py-1.5 rounded-full border border-maroon/20 tracking-widest uppercase text-xs font-bold">
            Wisdom Library
          </Badge>
          <h1 className="text-6xl font-black text-maroon mb-8 tracking-tight">
            Sacred <span className="text-gradient-gold">Teachings</span>
          </h1>
          <p className="text-xl text-navy/70 leading-relaxed max-w-2xl mx-auto">
            Explore Buddha's teachings and access books you can read online or download for later practice.
          </p>
        </div>

        {isLoading ? (
          <div className="h-64 flex flex-col items-center justify-center gap-4 text-maroon/30">
            <Loader2 className="size-10 animate-spin" />
            <span className="font-bold uppercase tracking-widest text-xs">Loading Teachings...</span>
          </div>
        ) : teachings.length === 0 ? (
          <div className="flex flex-col items-center justify-center p-20 border-4 border-dashed border-maroon/10 rounded-[3rem] bg-white/50 backdrop-blur-sm">
            <div className="size-24 bg-maroon/5 rounded-full flex items-center justify-center mb-8">
              <Sprout className="size-12 text-maroon animate-pulse" />
            </div>
            <h2 className="text-3xl font-bold text-maroon mb-4">Dhamma Articles Coming Soon</h2>
            <p className="text-navy/50 text-center max-w-md">
              Our library of sacred texts and wise reflections is currently being indexed for better wisdom discovery.
            </p>
          </div>
        ) : (
          <>
            <div className="bg-white rounded-[2rem] border border-gold/10 shadow-xl shadow-maroon/5 p-6 mb-10 space-y-5">
              <div className="flex flex-col md:flex-row md:items-center gap-4">
                <div className="relative flex-1">
                  <input
                    type="text"
                    placeholder="Search teachings..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full h-12 bg-cream/30 border-2 border-gold/10 rounded-xl px-4 focus:border-maroon focus:bg-white outline-none transition-all font-medium text-navy"
                  />
                </div>
                <div className="flex items-center gap-3">
                  <div className="relative">
                    <Globe className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-navy/30 pointer-events-none" />
                    <select
                      value={selectedLanguage}
                      onChange={(e) => setSelectedLanguage(e.target.value as "all" | "mm" | "en" | "th")}
                      className="h-11 pl-10 pr-4 rounded-xl border-2 border-gold/10 bg-cream/30 font-bold text-navy/60 uppercase tracking-widest text-xs focus:border-maroon focus:bg-white outline-none transition-all"
                      title="Filter by language"
                      aria-label="Filter by language"
                    >
                      <option value="all">Any language</option>
                      <option value="mm">MM</option>
                      <option value="en">EN</option>
                      <option value="th">TH</option>
                    </select>
                  </div>
                  <select
                    value={sortOrder}
                    onChange={(e) => setSortOrder(e.target.value as "newest" | "oldest")}
                    className="h-11 px-4 rounded-xl border-2 border-gold/10 bg-cream/30 font-bold text-navy/60 uppercase tracking-widest text-xs focus:border-maroon focus:bg-white outline-none transition-all"
                  >
                    <option value="newest">Newest</option>
                    <option value="oldest">Oldest</option>
                  </select>
                  <button
                    type="button"
                    onClick={() => {
                      setSearch("");
                      setSelectedCategory("all");
                      setSelectedLanguage("all");
                      setSortOrder("newest");
                    }}
                    className="h-11 px-4 rounded-xl border-2 border-maroon/20 text-maroon font-bold text-xs uppercase tracking-widest hover:bg-maroon hover:text-white transition-colors"
                  >
                    Clear Filters
                  </button>
                </div>
              </div>
              <div className="flex flex-wrap items-center gap-2">
                {categories.map((cat) => {
                  const isZero = cat.id !== "all" && cat.count === 0;
                  return (
                  <button
                      key={cat.id}
                      type="button"
                      onClick={() => setSelectedCategory(cat.id)}
                      disabled={isZero}
                      title={isZero ? "No posts yet" : ""}
                      className={cn(
                        "h-10 px-4 rounded-full border font-bold text-xs uppercase tracking-widest transition-colors",
                        isZero && "opacity-40 cursor-not-allowed border-gold/5 bg-cream/20 text-navy/30",
                        selectedCategory === cat.id
                          ? "bg-maroon text-white border-maroon"
                          : "bg-cream/30 text-navy/50 border-gold/10 hover:border-gold/30"
                      )}
                    >
                      {cat.label} <span className="ml-1 text-[10px] opacity-70">({cat.count})</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {filteredTeachings.length === 0 ? (
              <div className="flex flex-col items-center justify-center p-16 border-2 border-dashed border-gold/20 rounded-[2rem] bg-white/70 text-navy/40">
                <Sprout className="size-10 mb-3" />
                <p className="font-bold">No teachings match your search.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
                {sortedTeachings.map((teaching, index) => {
                  const documentUrl = resolveFileUrl(teaching.documentUrl);
                  const coverUrl = resolveFileUrl(teaching.coverImageUrl);
                  const translation =
                    selectedLanguage === "all"
                      ? pickTranslation(teaching.translations)
                      : pickTranslation(teaching.translations, [selectedLanguage]);
                  const isBook = String(teaching.category || "").toLowerCase() === "dhamma_book";
                  return (
                    <motion.div
                      key={teaching.id}
                      initial={{ opacity: 0, y: 20 }}
                      whileInView={{ opacity: 1, y: 0 }}
                      transition={{ duration: 0.5, delay: index * 0.05 }}
                      viewport={{ once: true }}
                      className="group bg-white rounded-[2rem] border border-gold/10 shadow-lg shadow-maroon/5 flex flex-col overflow-hidden transition-all hover:-translate-y-0.5 hover:shadow-xl hover:shadow-maroon/10"
                    >
                      {isBook && (
                        <div className="relative w-full h-44 bg-cream/30 border-b border-gold/10">
                          {coverUrl ? (
                            <Image
                              src={coverUrl}
                              alt={translation?.title || "Book cover"}
                              fill
                              className="object-cover"
                              unoptimized
                            />
                          ) : (
                            <div className="absolute inset-0 flex items-center justify-center text-navy/30 font-bold uppercase tracking-widest text-xs">
                              No cover
                            </div>
                          )}
                        </div>
                      )}

                      <div className="p-6 flex flex-col flex-1">
                      <div className="flex items-center justify-between mb-3 min-h-7">
                        <Badge className="bg-maroon/5 text-maroon border-maroon/10 uppercase tracking-widest text-[10px] font-black">
                          {teaching.category === "dhamma_book" ? "Dhamma Book" : (teaching.category || "dhamma")}
                        </Badge>
                        <div className="flex items-center gap-2 text-navy/30">
                          {teaching.audioUrl && <Music2 className="size-4" />}
                          {teaching.videoUrl && <Video className="size-4" />}
                          {teaching.documentUrl && <FileText className="size-4" />}
                        </div>
                      </div>

                      <h3 className="text-2xl font-black text-maroon mb-1.5 leading-tight line-clamp-2 min-h-[3.25rem]">
                        {translation?.title || "Untitled"}
                      </h3>
                      <p className="text-xs text-gold-dark font-bold uppercase tracking-widest mb-3 min-h-4">
                        {translation?.locale || ""}
                      </p>

                      {!isBook && (
                        <p className="text-navy/60 text-sm leading-relaxed break-words whitespace-pre-line line-clamp-3 min-h-[4.25rem]">
                          {translation?.content || "Summary coming soon."}
                        </p>
                      )}
                      {isBook && (
                        <p className="text-navy/50 text-sm leading-relaxed min-h-[4.25rem]">
                          PDF / eBook available to read and download.
                        </p>
                      )}

                      <div className="mt-5 space-y-3 flex-1 flex flex-col">
                        <p className="text-[11px] font-bold text-navy/40 uppercase tracking-widest min-h-4">
                          {teaching.teacher?.name ? (
                            <>Teacher: <span className="text-navy/70">{teaching.teacher.name}</span></>
                          ) : (
                            ""
                          )}
                        </p>

                        <div className="flex flex-wrap items-center gap-3 mt-auto">
                          <Link
                            href={`/teachings/${teaching.id}`}
                            className="inline-flex items-center gap-2 text-maroon font-bold text-sm hover:text-gold transition-colors"
                          >
                            {isBook ? "Open Book" : "Read Teaching"}
                            <ArrowUpRight className="size-4" />
                          </Link>
                          {documentUrl && (
                            <a
                              href={documentUrl}
                              download
                              className="inline-flex items-center gap-2 text-navy/60 font-bold text-sm hover:text-maroon transition-colors"
                            >
                              Download
                              <FileText className="size-4" />
                            </a>
                          )}
                        </div>
                      </div>
                      </div>
                    </motion.div>
                  );
                })}
              </div>
            )}
          </>
        )}
      </section>
    </div>
  );
}

"use client";

import { useState } from "react";
import { 
  ChevronDown, 
  ChevronUp, 
  ChevronsUpDown, 
  Eye, 
  EyeOff,
  Search,
  Settings2,
  ArrowLeft,
  ArrowRight,
  Loader2
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export interface Column<T> {
  id: string;
  header: string;
  accessorKey?: keyof T | string;
  cell?: (item: T) => React.ReactNode;
  sortable?: boolean;
  className?: string;
  hideable?: boolean;
}

interface DataTableProps<T> {
  columns: Column<T>[];
  data: T[];
  isLoading?: boolean;
  // Sorting
  sortBy?: string;
  sortOrder?: "asc" | "desc";
  onSort?: (field: string, order: "asc" | "desc") => void;
  // Pagination
  page: number;
  totalPages: number;
  total?: number;
  onPageChange: (page: number) => void;
  // Search
  search?: string;
  onSearchChange?: (value: string) => void;
  searchPlaceholder?: string;
  // Extra filters
  children?: React.ReactNode;
}

export function DataTable<T>({
  columns,
  data,
  isLoading,
  sortBy,
  sortOrder,
  onSort,
  page,
  totalPages,
  total,
  onPageChange,
  search,
  onSearchChange,
  searchPlaceholder = "Search...",
  children,
}: DataTableProps<T>) {
  const [visibleColumns, setVisibleColumns] = useState<string[]>(
    columns.map((c) => c.id)
  );
  const [showSettings, setShowSettings] = useState(false);

  const toggleColumn = (id: string) => {
    setVisibleColumns((prev) =>
      prev.includes(id) ? prev.filter((c) => c !== id) : [...prev, id]
    );
  };

  const handleSort = (id: string) => {
    if (!onSort) return;
    if (sortBy === id) {
      onSort(id, sortOrder === "asc" ? "desc" : "asc");
    } else {
      onSort(id, "desc");
    }
  };

  return (
    <div className="space-y-6">
      {/* Search & Actions Bar */}
      <div className="flex flex-col md:flex-row items-center gap-4 bg-white p-4 rounded-[1.5rem] border border-gold/10 shadow-sm">
        {onSearchChange && (
          <div className="relative flex-1 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 size-5 text-navy/20 group-focus-within:text-maroon transition-colors" />
            <input
              type="text"
              placeholder={searchPlaceholder}
              value={search}
              onChange={(e) => onSearchChange(e.target.value)}
              className="w-full h-12 bg-cream/30 border-none rounded-xl pl-12 pr-4 focus:ring-2 focus:ring-maroon/20 outline-none font-medium text-navy"
            />
          </div>
        )}

        {children}

        <div className="relative">
          <Button
            variant="outline"
            onClick={() => setShowSettings(!showSettings)}
            className="h-12 border-gold/20 rounded-xl px-4 flex gap-2 font-bold text-navy/60"
          >
            <Settings2 className="size-5" />
            Columns
          </Button>

          {showSettings && (
            <div className="absolute right-0 mt-2 w-56 bg-white border border-gold/20 rounded-2xl shadow-xl z-50 p-4 animate-in fade-in zoom-in-95">
              <p className="text-[10px] font-black uppercase tracking-widest text-navy/40 mb-3 ml-1">Visible Columns</p>
              <div className="space-y-1">
                {columns.filter(c => c.hideable !== false).map((col) => (
                  <button
                    key={col.id}
                    onClick={() => toggleColumn(col.id)}
                    className={cn(
                      "w-full flex items-center justify-between p-2 rounded-lg text-sm font-bold transition-colors text-left",
                      visibleColumns.includes(col.id) 
                        ? "bg-maroon/5 text-maroon" 
                        : "text-navy/40 hover:bg-navy/5"
                    )}
                  >
                    {col.header}
                    {visibleColumns.includes(col.id) ? (
                      <Eye className="size-4" />
                    ) : (
                      <EyeOff className="size-4" />
                    )}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-[2.5rem] border border-gold/10 shadow-xl shadow-maroon/5 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-cream/40 border-b border-gold/10">
                {columns
                  .filter((c) => visibleColumns.includes(c.id))
                  .map((col) => (
                    <th
                      key={col.id}
                      className={cn(
                        "p-6 py-4 text-xs font-black text-navy/40 uppercase tracking-widest",
                        col.sortable && "cursor-pointer hover:text-maroon transition-colors",
                        col.className
                      )}
                      onClick={() => col.sortable && handleSort(col.id)}
                    >
                      <div className="flex items-center gap-1">
                        {col.header}
                        {col.sortable && (
                          sortBy === col.id ? (
                            sortOrder === "asc" ? <ChevronUp className="size-4" /> : <ChevronDown className="size-4" />
                          ) : (
                            <ChevronsUpDown className="size-4 opacity-30" />
                          )
                        )}
                      </div>
                    </th>
                  ))}
              </tr>
            </thead>
            <tbody className="text-navy/70 font-medium">
              {isLoading ? (
                <tr>
                  <td colSpan={visibleColumns.length} className="p-20 text-center">
                    <Loader2 className="size-10 animate-spin mx-auto text-maroon/20 mb-4" />
                    <p className="text-xs font-black uppercase tracking-widest text-navy/20">Loading Data...</p>
                  </td>
                </tr>
              ) : data.length === 0 ? (
                <tr>
                  <td colSpan={visibleColumns.length} className="p-20 text-center">
                    <p className="font-bold text-navy/30">No records found.</p>
                  </td>
                </tr>
              ) : (
                data.map((item, idx) => (
                  <tr key={idx} className="border-b border-gold/5 last:border-none hover:bg-cream/20 transition-colors">
                    {columns
                      .filter((c) => visibleColumns.includes(c.id))
                      .map((col) => (
                        <td key={col.id} className={cn("p-6", col.className)}>
                          {col.cell ? col.cell(item) : (item as any)[col.accessorKey!]}
                        </td>
                      ))}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Pagination Footer */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="flex flex-col gap-1">
          <p className="text-[10px] font-black text-navy/30 uppercase tracking-[0.2em]">
            Page {page} of {totalPages || 1}
          </p>
          {total !== undefined && (
            <p className="text-[10px] font-bold text-maroon/40 uppercase tracking-widest">
              Total {total} Records
            </p>
          )}
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            className="h-10 rounded-xl border-gold/20 font-bold text-navy/60"
            disabled={page <= 1}
            onClick={() => onPageChange(page - 1)}
          >
            <ArrowLeft className="size-4 mr-2" /> Prev
          </Button>
          <Button
            variant="outline"
            className="h-10 rounded-xl border-gold/20 font-bold text-navy/60"
            disabled={page >= totalPages}
            onClick={() => onPageChange(page + 1)}
          >
            Next <ArrowRight className="size-4 ml-2" />
          </Button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { 
  Loader2, 
  Save, 
  Upload, 
  Info,
  Calendar,
  Languages,
  MapPin,
  Clock,
  Sparkles,
  Plus,
  Trash2
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import api from "@/lib/api";
import { cn } from "@/lib/utils";

const eventSchema = z.object({
  title: z.string().min(3, "English Title must be at least 3 characters"),
  titleMm: z.string().min(1, "Myanmar Title is required"),
  description: z.string().optional().or(z.literal("")),
  descriptionMm: z.string().optional().or(z.literal("")),
  date: z.string().min(1, "Start Date & Time is required"),
  endDate: z.string().optional().or(z.literal("")),
  location: z.string().optional().or(z.literal("")),
  image: z.string().optional().or(z.literal("")),
  mainSponsor: z.string().optional().or(z.literal("")),
  mainSponsorMm: z.string().optional().or(z.literal("")),
  coSponsors: z.array(z.object({
    name: z.string().min(1, "Name is required"),
    nameMm: z.string().optional().or(z.literal("")),
  })).optional(),
  isActive: z.boolean(),
});

type EventFormValues = z.infer<typeof eventSchema>;

interface EventFormProps {
  initialData?: any;
  isEditing?: boolean;
}

export function EventForm({ initialData, isEditing = false }: EventFormProps) {
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
    register,
    handleSubmit,
    control,
    formState: { errors },
  } = useForm<EventFormValues>({
    resolver: zodResolver(eventSchema),
    defaultValues: {
      ...initialData,
      date: initialData?.date ? new Date(initialData.date).toISOString().slice(0, 16) : "",
      endDate: initialData?.endDate ? new Date(initialData.endDate).toISOString().slice(0, 16) : "",
      isActive: initialData?.isActive ?? true,
      coSponsors: initialData?.coSponsors || [],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control,
    name: "coSponsors",
  });

  const onSubmit = async (values: EventFormValues) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = {
        ...values,
        date: new Date(values.date).toISOString(),
        endDate: values.endDate ? new Date(values.endDate).toISOString() : undefined,
        description: values.description || undefined,
        descriptionMm: values.descriptionMm || undefined,
        location: values.location || undefined,
        image: values.image || undefined,
        mainSponsor: values.mainSponsor || undefined,
        mainSponsorMm: values.mainSponsorMm || undefined,
        coSponsors: values.coSponsors?.length ? values.coSponsors : undefined,
      };

      if (isEditing) {
        await api.put(`/events/${initialData.id}`, data);
      } else {
        await api.post("/events", data);
      }
      router.push("/admin/events");
      router.refresh();
    } catch (err: any) {
      console.error("❌ Event Submit Error:", err.response?.data || err.message);
      setError(err.response?.data?.message || "Something went wrong. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-10 max-w-5xl text-navy">
      {error && (
        <div className="bg-red-50 text-red-600 p-6 rounded-2xl border border-red-100 font-myanmar flex items-center gap-3 shadow-sm">
          <Info className="size-5 shrink-0" />
          {error}
        </div>
      )}

      {/* Main Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-10 text-navy">
        {/* Left Side: English Info */}
        <div className="space-y-8 bg-white p-8 rounded-[2.5rem] border border-gold/10 shadow-xl shadow-maroon/5">
          <div className="flex items-center gap-4 mb-2">
            <div className="size-10 rounded-xl bg-maroon/5 flex items-center justify-center">
              <Sparkles className="size-5 text-maroon" />
            </div>
            <h3 className="font-black text-maroon uppercase tracking-tight text-xl">English Information</h3>
          </div>

          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-navy/40 uppercase tracking-widest ml-4">Event Title</label>
              <input 
                {...register("title")}
                className="w-full h-16 bg-cream/30 border-2 border-gold/10 rounded-2xl px-6 focus:border-maroon focus:bg-white outline-none transition-all font-bold text-navy"
                placeholder="Ex: Vesak Day Celebration"
              />
              {errors.title && <p className="text-[10px] text-red-500 font-bold ml-4 uppercase">{errors.title.message}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-navy/40 uppercase tracking-widest ml-4">Description</label>
              <textarea 
                {...register("description")}
                rows={4}
                className="w-full bg-cream/30 border-2 border-gold/10 rounded-2xl p-6 focus:border-maroon focus:bg-white outline-none transition-all font-medium text-navy resize-none"
                placeholder="Details about the event..."
              />
            </div>
          </div>
        </div>

        {/* Right Side: Myanmar Info */}
        <div className="space-y-8 bg-white p-8 rounded-[2.5rem] border border-gold/10 shadow-xl shadow-maroon/5">
          <div className="flex items-center gap-4 mb-2">
            <div className="size-10 rounded-xl bg-gold/5 flex items-center justify-center">
              <Languages className="size-5 text-gold" />
            </div>
            <h3 className="font-black text-maroon uppercase tracking-tight text-xl font-myanmar">မြန်မာဘာသာ အချက်အလက်</h3>
          </div>

          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-navy/40 uppercase tracking-widest ml-4">ပွဲအမည်</label>
              <input 
                {...register("titleMm")}
                className="w-full h-16 bg-cream/30 border-2 border-gold/10 rounded-2xl px-6 focus:border-maroon focus:bg-white outline-none transition-all font-bold text-navy font-myanmar"
                placeholder="ဥပမာ- ကဆုန်လပြည့် ဗုဒ္ဓနေ့ အခမ်းအနား"
              />
              {errors.titleMm && <p className="text-[10px] text-red-500 font-bold ml-4 font-myanmar">{errors.titleMm.message}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-navy/40 uppercase tracking-widest ml-4">ပွဲအကြောင်းအရာ</label>
              <textarea 
                {...register("descriptionMm")}
                rows={4}
                className="w-full bg-cream/30 border-2 border-gold/10 rounded-2xl p-6 focus:border-maroon focus:bg-white outline-none transition-all font-medium text-navy resize-none font-myanmar"
                placeholder="ဤပွဲအကြောင်းကို ရှင်းပြပေးပါ..."
              />
            </div>
          </div>
        </div>
      </div>

      {/* Schedule & Location */}
      <div className="bg-white p-10 rounded-[3rem] border border-gold/10 shadow-xl shadow-maroon/5 space-y-10">
        <h3 className="text-2xl font-black text-maroon uppercase tracking-tight flex items-center gap-4">
          <Calendar className="size-8 text-gold" /> 
          Schedule & Venue
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          <div className="col-span-1 md:col-span-2 space-y-2">
            <label className="text-xs font-black text-navy/40 uppercase tracking-widest ml-4">Start Date & Time</label>
            <div className="relative">
              <input 
                {...register("date")}
                type="datetime-local"
                className="w-full h-16 bg-cream/50 border-2 border-gold/10 rounded-2xl px-6 focus:border-maroon focus:bg-white outline-none transition-all font-bold text-navy appearance-none"
              />
              <Clock className="absolute right-6 top-1/2 -translate-y-1/2 size-5 text-navy/20 pointer-events-none" />
