                <ImageIcon className="size-5 text-maroon" />
              </div>
              <div>
                <p className="font-black text-maroon uppercase tracking-tight text-lg">Book Cover</p>
                <p className="text-xs text-navy/40 font-bold">Upload a cover image (recommended)</p>
