                    onClick={() => setIsMobileMenuOpen(false)}
                    className={cn(
                      "flex items-center gap-4 px-6 py-4 rounded-2xl text-sm font-bold uppercase tracking-widest transition-all",
                      pathname === link.href
                        ? "bg-maroon text-white shadow-xl shadow-maroon/20"
